<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Database\Eloquent\Relations\HasOne;
use Illuminate\Database\Eloquent\SoftDeletes;
use Illuminate\Support\Str;

class Hunt extends Model
{
    use SoftDeletes;

    protected $fillable = [
        'user_id', 'title', 'location_name', 'latitude', 'longitude',
        'country', 'region', 'is_coastal', 'starts_at', 'ends_at',
        'notes', 'share_token', 'is_public',
    ];

    protected function casts(): array
    {
        return [
            'latitude' => 'decimal:7',
            'longitude' => 'decimal:7',
            'is_coastal' => 'boolean',
            'is_public' => 'boolean',
            'starts_at' => 'datetime',
            'ends_at' => 'datetime',
        ];
    }

    protected static function booted(): void
    {
        static::creating(function (Hunt $hunt) {
            if (!$hunt->share_token) {
                $hunt->share_token = Str::random(32);
            }
        });
    }

    public function user(): BelongsTo
    {
        return $this->belongsTo(User::class);
    }

    public function checklistItems(): HasMany
    {
        return $this->hasMany(HuntChecklistItem::class)->orderBy('category')->orderBy('sort_order');
    }

    public function briefing(): HasOne
    {
        return $this->hasOne(HuntBriefing::class);
    }

    public function getShareUrlAttribute(): string
    {
        return route('hunts.shared', $this->share_token);
    }

    public function getCheckedCountAttribute(): int
    {
        return $this->checklistItems()->where('is_checked', true)->count();
    }

    public function getTotalItemsCountAttribute(): int
    {
        return $this->checklistItems()->count();
    }
}
