<?php

namespace App\Services\Providers;

class DemoWeatherProvider implements WeatherProviderInterface
{
    public function getForecast(float $lat, float $lng, \DateTime $date): array
    {
        $month = (int) $date->format('n');
        $isWinter = in_array($month, [11, 12, 1, 2]);
        $isSummer = in_array($month, [6, 7, 8]);
        $isSpring = in_array($month, [3, 4, 5]);

        $baseTemp = match(true) {
            $isWinter => rand(1, 7),
            $isSpring => rand(8, 15),
            $isSummer => rand(16, 25),
            default => rand(9, 16),
        };

        $conditions = $isSummer
            ? ['Partly Cloudy', 'Sunny', 'Clear', 'Light Breeze', 'Warm & Overcast']
            : ($isWinter
                ? ['Overcast', 'Light Rain', 'Cold & Clear', 'Drizzle', 'Foggy']
                : ['Partly Cloudy', 'Light Showers', 'Mild & Breezy', 'Overcast', 'Clear Spells']);

        $hours = [];
        for ($h = 5; $h <= 21; $h++) {
            $tempVariation = rand(-2, 3);
            $hours[] = [
                'time' => sprintf('%02d:00', $h),
                'temp_c' => $baseTemp + $tempVariation,
                'feels_like_c' => $baseTemp + $tempVariation - rand(1, 3),
                'condition' => $conditions[array_rand($conditions)],
                'wind_mph' => rand(3, 20),
                'wind_direction' => ['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'][array_rand(['N', 'NE', 'E', 'SE', 'S', 'SW', 'W', 'NW'])],
                'precipitation_chance' => $isWinter ? rand(30, 80) : ($isSummer ? rand(5, 35) : rand(15, 55)),
                'humidity' => rand(55, 90),
                'pressure_mb' => rand(1005, 1030),
            ];
        }

        return [
            'date' => $date->format('Y-m-d'),
            'location' => ['lat' => $lat, 'lng' => $lng],
            'summary' => $conditions[0] . ", highs of {$baseTemp}°C with " . ($isWinter ? 'cold' : 'moderate') . " winds",
            'sunrise' => $isSummer ? '05:15' : ($isWinter ? '07:45' : '06:30'),
            'sunset' => $isSummer ? '21:15' : ($isWinter ? '16:00' : '18:45'),
            'temp_high_c' => $baseTemp + 3,
            'temp_low_c' => $baseTemp - 3,
            'avg_wind_mph' => rand(5, 15),
            'precipitation_chance' => $isWinter ? rand(40, 70) : rand(10, 40),
            'hourly' => $hours,
        ];
    }

    public function getProviderName(): string
    {
        return 'demo';
    }
}
