<?php

namespace App\Services\Providers;

class DemoTideProvider implements TideProviderInterface
{
    public function getTides(float $lat, float $lng, \DateTime $date): array
    {
        $baseHour = rand(1, 5);

        $tides = [
            [
                'type' => 'high',
                'time' => sprintf('%02d:%02d', $baseHour, rand(0, 59)),
                'height_m' => round(rand(40, 65) / 10, 1),
            ],
            [
                'type' => 'low',
                'time' => sprintf('%02d:%02d', $baseHour + 6, rand(0, 59)),
                'height_m' => round(rand(5, 20) / 10, 1),
            ],
            [
                'type' => 'high',
                'time' => sprintf('%02d:%02d', $baseHour + 12, rand(0, 59)),
                'height_m' => round(rand(38, 62) / 10, 1),
            ],
            [
                'type' => 'low',
                'time' => sprintf('%02d:%02d', min($baseHour + 18, 23), rand(0, 59)),
                'height_m' => round(rand(8, 22) / 10, 1),
            ],
        ];

        $springNeap = rand(0, 1) ? 'spring' : 'neap';

        return [
            'date' => $date->format('Y-m-d'),
            'location' => ['lat' => $lat, 'lng' => $lng],
            'tides' => $tides,
            'tide_type' => $springNeap,
            'tidal_range_m' => round($tides[0]['height_m'] - $tides[1]['height_m'], 1),
            'best_fishing_windows' => [
                [
                    'start' => sprintf('%02d:00', max(0, (int)explode(':', $tides[0]['time'])[0] - 2)),
                    'end' => sprintf('%02d:00', min(23, (int)explode(':', $tides[0]['time'])[0] + 1)),
                    'reason' => '2 hours before to 1 hour after high tide — peak feeding activity',
                ],
                [
                    'start' => sprintf('%02d:00', max(0, (int)explode(':', $tides[2]['time'])[0] - 2)),
                    'end' => sprintf('%02d:00', min(23, (int)explode(':', $tides[2]['time'])[0] + 1)),
                    'reason' => 'Second high tide window — good for evening session',
                ],
            ],
        ];
    }

    public function getProviderName(): string
    {
        return 'demo';
    }
}
