    public function toggleChecklistItem(Request $request, Hunt $hunt, int $itemId)
    {
        $this->authorize('update', $hunt);

        $item = $hunt->checklistItems()->findOrFail($itemId);
        $item->update(['is_checked' => !$item->is_checked]);

        return response()->json([
            'checked' => $item->is_checked,
            'checked_count' => $hunt->checklistItems()->where('is_checked', true)->count(),
            'total' => $hunt->checklistItems()->count(),
        ]);
    }

    public function regenerateBriefing(Hunt $hunt, HuntBriefingService $briefingService)
    {
        $this->authorize('update', $hunt);

        $briefingService->generateBriefing($hunt);

        return redirect()->route('hunts.show', $hunt)->with('success', 'Briefing regenerated with fresh data!');
    }
}
</boltAction>

<boltAction type="file" filePath="app/Http/Controllers/ProfileController.php" contentType="text/x-php">
<?php

namespace App\Http\Controllers;

use App\Models\User;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Storage;

class ProfileController extends Controller
{
    public function show(User $user)
    {
        $user->load('badges', 'roles');

        $posts = $user->posts()
            ->with('images')
            ->withCount(['likes', 'allComments'])
            ->where('is_visible', true)
            ->latest()
            ->take(6)
            ->get();

        $hunts = $user->hunts()
            ->latest('starts_at')
            ->take(4)
            ->get();

        $stats = [
            'posts' => $user->posts()->count(),
            'hunts' => $user->hunts()->count(),
            'species' => $user->posts()->whereNotNull('species')->distinct('species')->count('species'),
            'likes_received' => $user->posts()->withCount('likes')->get()->sum('likes_count'),
        ];

        return view('profile.show', compact('user', 'posts', 'hunts', 'stats'));
    }

    public function edit()
    {
        return view('profile.edit', ['user' => auth()->user()]);
    }

    public function update(Request $request)
    {
        $user = auth()->user();

        $validated = $request->validate([
            'name' => 'required|string|max:255',
            'bio' => 'nullable|string|max:500',
            'location' => 'nullable|string|max:255',
            'avatar' => 'nullable|image|mimes:jpeg,jpg,png,webp|max:5120',
        ]);

        if ($request->hasFile('avatar')) {
            if ($user->avatar) {
                Storage::disk('public')->delete($user->avatar);
            }
            $validated['avatar'] = $request->file('avatar')->store('avatars', 'public');
        }

        $user->update($validated);

        return redirect()->route('profile.show', $user)->with('success', 'Profile updated!');
    }
}
</boltAction>

