<?php

namespace App\Services;

use App\Models\Hunt;
use App\Models\HuntBriefing;
use App\Models\HuntChecklistItem;
use App\Services\Providers\WeatherProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\SpeciesInfoProviderInterface;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\DB;

class HuntBriefingService
{
    public function __construct(
        private WeatherProviderInterface $weatherProvider,
        private TideProviderInterface $tideProvider,
        private SpeciesInfoProviderInterface $speciesProvider,
    ) {}

    public function generateBriefing(Hunt $hunt): HuntBriefing
    {
        $lat = $hunt->latitude ?? 51.5074;
        $lng = $hunt->longitude ?? -0.1278;
        $date = $hunt->starts_at;
        $month = (int) $date->format('n');

        $cacheKey = "hunt_briefing_{$hunt->id}";

        $weatherData = Cache::remember(
            "weather_{$lat}_{$lng}_{$date->format('Y-m-d')}",
            3600,
            fn() => $this->weatherProvider->getForecast($lat, $lng, $date)
        );

        $tideData = null;
        if ($hunt->is_coastal) {
            $tideData = Cache::remember(
                "tides_{$lat}_{$lng}_{$date->format('Y-m-d')}",
                3600,
                fn() => $this->tideProvider->getTides($lat, $lng, $date)
            );
        }

        $speciesData = Cache::remember(
            "species_{$lat}_{$lng}_{$month}_{$hunt->is_coastal}",
            86400,
            fn() => $this->speciesProvider->getSpeciesForLocation($lat, $lng, $month, $hunt->is_coastal)
        );

        $suggestions = $this->generateSuggestions($weatherData, $tideData, $speciesData, $hunt);

        return DB::transaction(function () use ($hunt, $weatherData, $tideData, $speciesData, $suggestions) {
            $hunt->briefing()?->delete();
            $hunt->checklistItems()->delete();

            $briefing = HuntBriefing::create([
                'hunt_id' => $hunt->id,
                'weather_data' => $weatherData,
                'tide_data' => $tideData,
                'species_data' => $speciesData,
                'suggestions' => $suggestions,
                'weather_provider' => $this->weatherProvider->getProviderName(),
                'tide_provider' => $hunt->is_coastal ? $this->tideProvider->getProviderName() : null,
                'species_provider' => $this->speciesProvider->getProviderName(),
                'generated_at' => now(),
                'expires_at' => now()->addHours(6),
            ]);

            $this->generateChecklist($hunt, $weatherData, $tideData, $speciesData, $suggestions);

            return $briefing;
        });
    }

    private function generateSuggestions(array $weather, ?array $tides, array $species, Hunt $hunt): array
    {
        $suggestions = [];

        // Timing tips
        $timingTips = [];
        $timingTips[] = "Sunrise: {$weather['sunrise']} / Sunset: {$weather['sunset']}";

        if ($weather['avg_wind_mph'] > 15) {
            $timingTips[] = "⚠️ Windy conditions expected — seek sheltered spots and use heavier weights.";
        }

        if ($weather['precipitation_chance'] > 50) {
            $timingTips[] = "🌧️ Rain likely — fish often feed more actively before and during light rain.";
        }

        if ($tides) {
            foreach ($tides['best_fishing_windows'] ?? [] as $window) {
                $timingTips[] = "🎯 Best window: {$window['start']} - {$window['end']} — {$window['reason']}";
            }
        } else {
            $timingTips[] = "🌅 Dawn and dusk are typically the best times for freshwater fishing.";
        }

        $suggestions['timing_tips'] = $timingTips;

        // Bait suggestions
        $baitSuggestions = [];
        foreach ($species['species'] ?? [] as $sp) {
            $baits = implode(', ', array_slice($sp['recommended_bait'], 0, 3));
            $baitSuggestions[] = "{$sp['name']}: {$baits}";
        }
        $suggestions['bait_suggestions'] = $baitSuggestions;

        // Tackle suggestions
        $tackleSuggestions = [];
        foreach ($species['species'] ?? [] as $sp) {
            $tackleSuggestions[] = "{$sp['name']}: {$sp['recommended_tackle']}";
        }
        $suggestions['tackle_suggestions'] = $tackleSuggestions;

        // General tips
        $generalTips = [];
        $temp = $weather['temp_high_c'] ?? 15;
        if ($temp < 5) {
            $generalTips[] = "🧤 Dress warm! Multiple layers, thermal gloves, and a hot flask are essential.";
        } elseif ($temp > 20) {
            $generalTips[] = "☀️ Stay hydrated and use sun protection. Fish may be deeper during midday heat.";
        }

        $generalTips[] = "📱 Share your location with someone and let them know your plans.";
        $generalTips[] = "🗑️ Leave no trace — take all litter home.";

        if ($hunt->is_coastal) {
            $generalTips[] = "⚠️ Check tide times carefully and never fish with your back to the sea.";
            $generalTips[] = "🦀 If using crab bait, check local regulations on collection.";
        }

        $suggestions['general_tips'] = $generalTips;

        return $suggestions;
    }

    private function generateChecklist(Hunt $hunt, array $weather, ?array $tides, array $species, array $suggestions): void
    {
        $items = [];
        $order = 0;

        // Essential gear
        $essentials = [
            'Rod and reel (checked and working)',
            'Landing net',
            'Unhooking mat / fish-friendly surface',
            'Tackle box with hooks, weights, swivels',
            'Line cutters / scissors',
            'Forceps / disgorger',
            'Bait (see briefing suggestions)',
            'Rod rest / bank sticks',
            'Keep net or weigh sling',
        ];

        foreach ($essentials as $item) {
            $items[] = ['category' => 'Essential Tackle', 'item' => $item, 'sort_order' => $order++];
        }

        // Species-specific tackle
        foreach ($species['species'] ?? [] as $sp) {
            $items[] = [
                'category' => 'Species Tackle',
                'item' => "Rig for {$sp['name']}: {$sp['recommended_tackle']}",
                'notes' => $sp['tips'],
                'sort_order' => $order++,
            ];
        }

        // Bait
        foreach ($species['species'] ?? [] as $sp) {
            foreach (array_slice($sp['recommended_bait'], 0, 2) as $bait) {
                $items[] = [
                    'category' => 'Bait',
                    'item' => "{$bait} (for {$sp['name']})",
                    'sort_order' => $order++,
                ];
            }
        }

        // Clothing & comfort
        $temp = $weather['temp_high_c'] ?? 15;
        $clothing = ['Waterproof jacket'];

        if ($temp < 10) {
            $clothing = array_merge($clothing, [
                'Thermal base layer',
                'Warm fleece / hoodie',
                'Thermal gloves',
                'Warm hat / beanie',
                'Waterproof trousers',
                'Warm boots',
                'Hot flask with tea/coffee',
            ]);
        } elseif ($temp < 18) {
            $clothing = array_merge($clothing, [
                'Hoodie / light fleece',
                'Waterproof trousers',
                'Wellies or waterproof boots',
                'Flask with hot drink',
            ]);
        } else {
            $clothing = array_merge($clothing, [
                'Sun hat / cap',
                'Sunglasses (polarised)',
                'Suncream SPF 30+',
                'Plenty of water',
                'Light breathable clothing',
            ]);
        }

        if ($weather['precipitation_chance'] > 40) {
            $clothing[] = 'Umbrella / brolly';
        }

        foreach ($clothing as $item) {
            $items[] = ['category' => 'Clothing & Comfort', 'item' => $item, 'sort_order' => $order++];
        }

        // Food & drink
        $food = [
            'Packed lunch / snacks',
            'Water bottle (at least 1L)',
            'Energy bars',
        ];
        foreach ($food as $item) {
            $items[] = ['category' => 'Food & Drink', 'item' => $item, 'sort_order' => $order++];
        }

        // Safety
        $safety = [
            'Phone (fully charged)',
            'First aid kit',
            'Headtorch (with spare batteries)',
            'Fishing licence (check it\'s valid!)',
        ];
        if ($hunt->is_coastal) {
            $safety[] = 'Life jacket / buoyancy aid';
            $safety[] = 'Tide timetable (printed backup)';
            $safety[] = 'Whistle for emergencies';
        }
        foreach ($safety as $item) {
            $items[] = ['category' => 'Safety', 'item' => $item, 'sort_order' => $order++];
        }

        // Extras
        $extras = [
            'Camera / phone for photos',
            'Folding chair',
            'Bin bags for rubbish',
            'Towel / rag for hands',
        ];
        foreach ($extras as $item) {
            $items[] = ['category' => 'Extras', 'item' => $item, 'sort_order' => $order++];
        }

        foreach ($items as $item) {
            HuntChecklistItem::create(array_merge($item, [
                'hunt_id' => $hunt->id,
                'is_checked' => false,
            ]));
        }
    }
}
