<?php

namespace App\Http\Controllers;

use App\Models\Hunt;
use App\Services\BadgeService;
use App\Services\HuntBriefingService;
use Illuminate\Http\Request;

class HuntController extends Controller
{
    public function index()
    {
        $hunts = auth()->user()->hunts()
            ->withCount('checklistItems')
            ->latest('starts_at')
            ->paginate(12);

        return view('hunts.index', compact('hunts'));
    }

    public function create()
    {
        $this->authorize('create', Hunt::class);
        return view('hunts.create');
    }

    public function store(Request $request, HuntBriefingService $briefingService)
    {
        $this->authorize('create', Hunt::class);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'location_name' => 'required|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'country' => 'string|max:100',
            'region' => 'nullable|string|max:255',
            'is_coastal' => 'boolean',
            'starts_at' => 'required|date|after:now',
            'ends_at' => 'required|date|after:starts_at',
            'notes' => 'nullable|string|max:5000',
            'is_public' => 'boolean',
        ]);

        $hunt = Hunt::create([
            'user_id' => auth()->id(),
            ...$validated,
            'is_coastal' => $request->boolean('is_coastal'),
            'is_public' => $request->boolean('is_public'),
        ]);

        $briefingService->generateBriefing($hunt);

        app(BadgeService::class)->checkAndAwardBadges(auth()->user());

        return redirect()->route('hunts.show', $hunt)->with('success', 'Hunt planned! Check your briefing below. 🎯');
    }

    public function show(Hunt $hunt)
    {
        $this->authorize('view', $hunt);

        $hunt->load(['briefing', 'checklistItems', 'user']);

        $checkedCount = $hunt->checklistItems->where('is_checked', true)->count();
        $totalItems = $hunt->checklistItems->count();

        return view('hunts.show', compact('hunt', 'checkedCount', 'totalItems'));
    }

    public function edit(Hunt $hunt)
    {
        $this->authorize('update', $hunt);
        return view('hunts.edit', compact('hunt'));
    }

    public function update(Request $request, Hunt $hunt, HuntBriefingService $briefingService)
    {
        $this->authorize('update', $hunt);

        $validated = $request->validate([
            'title' => 'required|string|max:255',
            'location_name' => 'required|string|max:255',
            'latitude' => 'nullable|numeric|between:-90,90',
            'longitude' => 'nullable|numeric|between:-180,180',
            'country' => 'string|max:100',
            'region' => 'nullable|string|max:255',
            'is_coastal' => 'boolean',
            'starts_at' => 'required|date',
            'ends_at' => 'required|date|after:starts_at',
            'notes' => 'nullable|string|max:5000',
            'is_public' => 'boolean',
        ]);

        $hunt->update([
            ...$validated,
            'is_coastal' => $request->boolean('is_coastal'),
            'is_public' => $request->boolean('is_public'),
        ]);

        if ($request->boolean('regenerate_briefing')) {
            $briefingService->generateBriefing($hunt);
        }

        return redirect()->route('hunts.show', $hunt)->with('success', 'Hunt updated!');
    }

    public function destroy(Hunt $hunt)
    {
        $this->authorize('delete', $hunt);
        $hunt->delete();
        return redirect()->route('hunts.index')->with('success', 'Hunt deleted.');
    }

    public function shared(string $token)
    {
        $hunt = Hunt::where('share_token', $token)->firstOrFail();
        $hunt->load(['briefing', 'checklistItems', 'user']);

        $checkedCount = $hunt->checklistItems->where('is_checked', true)->count();
        $totalItems = $hunt->checklistItems->count();

        return view('hunts.shared', compact('hunt', 'checkedCount', 'totalItems'));
    }

    public function toggleChecklistItem(Request $request, Hunt $hunt, int $itemId)
    {
        $this->authorize('update', $hunt);

        $item = $hunt->checklistItems()->findOrFail($itemId);
        $item->update(['is_checked' => !$item->is_checked]);

        return response()->json([
            'checked' => $item->is_checked,
            'checked_count' => $hunt->checklistItems()->where('is_checked', true)->count(),
            'total' => $hunt->checklistItems()->count(),
        ]);
    }

    public function regenerateBriefing(Hunt $hunt, HuntBriefingService $briefingService)
    {
        $this->authorize('update', $hunt);

        $briefingService->generateBriefing($hunt);

        return redirect()->route('hunts.show', $hunt)->with('success', 'Briefing regenerated with fresh data!');
    }
}
