The issue is clear — SQLite doesn't support `HAVING` on non-aggregate queries. The `popular-catch` badge check uses `withCount('likes')->having(...)` which SQLite rejects. I need to refactor that query to use a subquery approach instead.

<boltArtifact id="fix-badge-service" title="Fix BadgeService SQLite compatibility">
<boltAction type="file" filePath="app/Services/BadgeService.php"><?php

namespace App\Services;

use App\Models\Badge;
use App\Models\Like;
use App\Models\Post;
use App\Models\User;

class BadgeService
{
    public function checkAndAwardBadges(User $user): void
    {
        $postCount = $user->posts()->count();
        $huntCount = $user->hunts()->count();
        $speciesCount = $user->posts()->whereNotNull('species')->distinct('species')->count('species');
        $commentCount = $user->comments()->count();
        $likeCount = $user->likes()->count();

        // Check if user has any post with 5+ likes (SQLite-compatible)
        $hasPopularCatch = $user->posts()
            ->whereExists(function ($query) {
                $query->selectRaw('1')
                    ->from('likes')
                    ->whereColumn('likes.likeable_id', 'posts.id')
                    ->where('likes.likeable_type', Post::class)
                    ->groupBy('likes.likeable_id')
                    ->havingRaw('COUNT(*) >= 5');
            })
            ->exists();

        $badgeChecks = [
            'first-catch' => $postCount >= 1,
            'five-catches' => $postCount >= 5,
            'ten-catches' => $postCount >= 10,
            'species-explorer' => $speciesCount >= 3,
            'species-master' => $speciesCount >= 10,
            'first-hunt' => $huntCount >= 1,
            'five-hunts' => $huntCount >= 5,
            'social-angler' => $commentCount >= 10,
            'popular-catch' => $hasPopularCatch,
            'keen-supporter' => $likeCount >= 20,
        ];

        foreach ($badgeChecks as $slug => $earned) {
            if ($earned) {
                $badge = Badge::where('slug', $slug)->first();
                if ($badge && !$user->badges()->where('badge_id', $badge->id)->exists()) {
                    $user->badges()->attach($badge->id, ['earned_at' => now()]);
                }
            }
        }
    }
}
