The issue is that Laravel generates `http://` asset URLs but the page is served over `https://` via the reverse proxy. I need to force HTTPS scheme and trust the proxy.

<boltArtifact id="fix-mixed-content" title="Fix mixed content - force HTTPS assets">
<boltAction type="file" filePath="app/Providers/AppServiceProvider.php"><?php

namespace App\Providers;

use App\Services\Providers\DemoSpeciesProvider;
use App\Services\Providers\DemoTideProvider;
use App\Services\Providers\DemoWeatherProvider;
use App\Services\Providers\SpeciesInfoProviderInterface;
use App\Services\Providers\TideProviderInterface;
use App\Services\Providers\WeatherProviderInterface;
use Illuminate\Support\Facades\Gate;
use Illuminate\Support\Facades\URL;
use Illuminate\Support\ServiceProvider;

class AppServiceProvider extends ServiceProvider
{
    public function register(): void
    {
        // Weather provider
        $this->app->bind(WeatherProviderInterface::class, function () {
            $provider = config('services.weather.provider', 'demo');
            return match ($provider) {
                default => new DemoWeatherProvider(),
            };
        });

        // Tide provider
        $this->app->bind(TideProviderInterface::class, function () {
            $provider = config('services.tide.provider', 'demo');
            return match ($provider) {
                default => new DemoTideProvider(),
            };
        });

        // Species provider
        $this->app->bind(SpeciesInfoProviderInterface::class, function () {
            $provider = config('services.species.provider', 'demo');
            return match ($provider) {
                default => new DemoSpeciesProvider(),
            };
        });
    }

    public function boot(): void
    {
        // Force HTTPS when behind a reverse proxy (Coolify, Replit, etc.)
        if ($this->app->environment('production') || isset($_SERVER['HTTP_X_FORWARDED_PROTO'])) {
            URL::forceScheme('https');
        }

        // Also force HTTPS if APP_URL starts with https
        if (str_starts_with(config('app.url', ''), 'https://')) {
            URL::forceScheme('https');
        }

        Gate::before(function ($user, $ability) {
            if ($user->isAdmin()) {
                return true;
            }
        });
    }
}
